/**
 * E2E tests for mdtldr CLI commands
 * Tests actual CLI execution against a test fixture directory
 */

import { execSync } from 'node:child_process'
import { describe, expect, it } from 'vitest'

const TEST_DIR = '/Users/alphab/Dev/LLM/DEV/TMP/memory'
const CLI = 'pnpm mdtldr'

const run = (args: string, options: { cwd?: string; expectError?: boolean } = {}): string => {
  const cwd = options.cwd ?? TEST_DIR
  try {
    return execSync(`${CLI} ${args}`, {
      cwd,
      encoding: 'utf-8',
      stdio: ['pipe', 'pipe', 'pipe'],
    }).trim()
  } catch (error: unknown) {
    if (options.expectError) {
      const execError = error as { stderr?: string; stdout?: string }
      return execError.stderr || execError.stdout || ''
    }
    throw error
  }
}

describe('mdtldr CLI e2e', () => {
  describe('--version', () => {
    it('shows version number', () => {
      const output = run('--version')
      expect(output).toMatch(/^\d+\.\d+\.\d+$/)
    })
  })

  describe('--help', () => {
    it('shows help with all commands', () => {
      const output = run('--help')
      expect(output).toContain('index')

export const summarizeDocument = (
  document: MdDocument,
  options: SummarizeOptions = {},
): DocumentSummary => {
  const level = options.level ?? 'summary'
  const maxTokens = options.maxTokens ?? TOKEN_BUDGETS[level]

  // Summarize all sections
  const sections = document.sections.map((s) => summarizeSection(s, level))

  // Calculate totals
  const originalTokens = document.metadata.tokenCount
  let summaryTokens = sections.reduce((acc, s) => acc + s.summaryTokens, 0)

  // If over budget, truncate sections
  if (summaryTokens > maxTokens) {
    // Simple truncation: reduce section summaries
    const ratio = maxTokens / summaryTokens
    summaryTokens = Math.floor(summaryTokens * ratio)
  }

  const compressionRatio =
    originalTokens > 0 ? 1 - summaryTokens / originalTokens : 0

  return {
    path: document.path,
    title: document.title,
    originalTokens,
    summaryTokens,
    compressionRatio,
    sections,
    keyTopics: extractTopics(document),
  }
}

